// src/services/firebase.js
// Replace the firebaseConfig values with your own from Firebase Console
// Go to: console.firebase.google.com → New Project → Web App → Copy config

import { initializeApp } from 'firebase/app';
import { getAuth } from 'firebase/auth';
import { getFirestore } from 'firebase/firestore';

const firebaseConfig = {
  apiKey: "AIzaSyClBC4qqcAwolSjkxsR_dPI09A9CDmuhJ8",
  authDomain: "skill-bridge-b0a0f.firebaseapp.com",
  databaseURL: "https://skill-bridge-b0a0f-default-rtdb.firebaseio.com",
  projectId: "skill-bridge-b0a0f",
  storageBucket: "skill-bridge-b0a0f.firebasestorage.app",
  messagingSenderId: "243005868806",
  appId: "1:243005868806:web:c282756b9f82a282412c87",
  measurementId: "G-F1RK01PNM0"
};

const app = initializeApp(firebaseConfig);

export const auth = getAuth(app);
export const db = getFirestore(app);
export default app;
